/**
 * AI JOKER-C2 EVT Memory Ledger
 *
 * Append-only JSONL ledger for semantic EVT/IPR-bound memory events.
 *
 * This module persists EvtMemoryEvent records generated by lib/evt-memory.ts.
 * It does not replace the governed runtime EVT ledger in lib/evt-ledger.ts.
 *
 * Separation:
 * - evt-ledger.ts stores governed RuntimeEvent records.
 * - evt-memory-ledger.ts stores semantic EVT/IPR-bound continuity records.
 *
 * Current canonical runtime:
 * - EVT-0015-AI
 * - previous EVT-0014-AI
 * - cycle UP-MESE-4
 *
 * Supported project domains:
 * - MATRIX
 * - U.S.E.
 * - CORPUS_ESOTEROLOGIA_ERMETICA
 * - APOKALYPSIS
 * - HBCE_ECOSISTEMA_AI
 * - GENERAL
 * - MULTI_DOMAIN
 *
 * Prototype note:
 * This local file adapter is suitable for local development and controlled
 * prototype use. Serverless production deployments should use persistent
 * external storage such as Postgres, KV, object storage, or another managed
 * append-only store.
 *
 * Serverless note:
 * On Vercel/serverless runtimes, local filesystem persistence may fail or
 * reset between invocations. In that case, append failures should be reported
 * as persistence failures while the generated memory event remains hash-verifiable.
 */

import { appendFile, mkdir, readFile, stat, writeFile } from "fs/promises";
import os from "os";
import path from "path";

import {
  sha256Short,
  type DocumentFamily,
  type EvtMemoryEvent,
  type ProjectDomain,
  type RuntimeDecision,
  type RuntimeState,
  type SemanticState
} from "./evt-memory";

const DEFAULT_LEDGER_FILENAME = "hbce-ai-joker-c2-evt-memory.jsonl";

export const DEFAULT_EVT_MEMORY_LEDGER_DIR =
  process.env.JOKER_EVT_MEMORY_LEDGER_DIR ||
  process.env.HBCE_EVT_MEMORY_LEDGER_DIR ||
  path.join(os.tmpdir(), "hbce-ai-joker-c2");

export const DEFAULT_EVT_MEMORY_LEDGER_FILE =
  process.env.JOKER_EVT_MEMORY_LEDGER_FILE ||
  process.env.HBCE_EVT_MEMORY_LEDGER_FILE ||
  path.join(DEFAULT_EVT_MEMORY_LEDGER_DIR, DEFAULT_LEDGER_FILENAME);

export type EvtMemoryLedgerAppendStatus =
  | "APPENDED"
  | "REJECTED"
  | "FAILED";

export type EvtMemoryLedgerReadStatus =
  | "READY"
  | "EMPTY"
  | "MISSING"
  | "FAILED";

export type EvtMemoryLedgerVerificationStatus =
  | "VERIFIABLE"
  | "PARTIAL"
  | "INVALID"
  | "UNVERIFIED";

export type EvtMemoryLedgerAppendResult = {
  status: EvtMemoryLedgerAppendStatus;
  evt?: string;
  prev?: string;
  ledgerPath: string;
  reason: string;
};

export type EvtMemoryLedgerReadResult = {
  status: EvtMemoryLedgerReadStatus;
  ledgerPath: string;
  events: EvtMemoryEvent[];
  invalidLines: number;
  reason: string;
};

export type EvtMemoryLedgerLookupResult = {
  found: boolean;
  event?: EvtMemoryEvent;
  ledgerPath: string;
  reason: string;
};

export type EvtMemoryLedgerSummary = {
  ledgerPath: string;
  totalEvents: number;
  lastEvent: string;
  lastTraceHash: string;
  invalidLines: number;
  verificationStatus: EvtMemoryLedgerVerificationStatus;
};

export type EvtMemoryLedgerIntegrityResult = {
  status: EvtMemoryLedgerVerificationStatus;
  ledgerPath: string;
  totalEvents: number;
  invalidLines: number;
  hashValid: boolean;
  chainContinuity: "LINEAR" | "PARTIAL" | "UNVERIFIED";
  warnings: string[];
};

export type EvtMemoryLedgerPublicEvent = {
  evt: string;
  prev: string;
  t: string;
  entity: string;
  ipr: string;
  sessionId: string;
  state: RuntimeState;
  decision: RuntimeDecision;
  documentFamily: DocumentFamily;
  projectDomain: ProjectDomain;
  activeDomains: ProjectDomain[];
  activeDocument: string | null;
  semanticTags: string[];
  userIntent: string;
  governedEvt: string | null;
  governedHash: string | null;
  opcProofId: string | null;
  opcChainHash: string | null;
  traceHash: string;
  memoryHash: string;
  legalCertification: false;
};

export type LedgerMemoryContext = {
  used: boolean;
  source:
    | "LEDGER_SESSION"
    | "LEDGER_IPR_CANONICAL"
    | "LEDGER_IPR_RECENT"
    | "NONE";
  text: string;
  semanticState: SemanticState | null;
  lastEventId: string | null;
};

const EVENT_KIND = "EVT_IPR_BOUND_MEMORY" as const;
const RUNTIME_ROLE = "IPR_RUNTIME_DEMONSTRATOR" as const;
const CANONICAL_SESSION_ID = "CANONICAL";
const MAX_CONTEXT_EVENTS = 10;
const MAX_CONTEXT_TEXT_CHARS = 12000;

const USE_DEMOCRATIC_BOUNDARY =
  "Identity verified first. Choice separated after. Vote anonymized. Process auditable.";

const HBCE_AI_BOUNDARY =
  "The AI model does not govern HBCE. HBCE governs the use of AI models.";

const NON_CERTIFICATION_STATEMENT =
  "EVT/IPR-bound memory preserves runtime continuity. It is not legal certification and does not replace audit, verification, legal review or user control.";

const ALL_PRIMARY_PROJECT_DOMAINS: ProjectDomain[] = [
  "MATRIX",
  "U.S.E.",
  "CORPUS_ESOTEROLOGIA_ERMETICA",
  "APOKALYPSIS",
  "HBCE_ECOSISTEMA_AI"
];

export async function ensureEvtMemoryLedger(
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<void> {
  const directory = path.dirname(ledgerPath);

  await mkdir(directory, { recursive: true });

  try {
    await stat(ledgerPath);
  } catch {
    await writeFile(ledgerPath, "", "utf8");
  }
}

export async function appendEvtMemoryEvent(
  event: EvtMemoryEvent,
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerAppendResult> {
  const eventRef = {
    evt: event.evt,
    prev: event.prev
  };

  try {
    await ensureEvtMemoryLedger(ledgerPath);

    if (!isEvtMemoryEventStructurallyValid(event)) {
      return {
        status: "REJECTED",
        evt: eventRef.evt,
        prev: eventRef.prev,
        ledgerPath,
        reason:
          "EVT memory event is structurally invalid and was not appended."
      };
    }

    if (!isEvtMemoryEventHashValid(event)) {
      return {
        status: "REJECTED",
        evt: eventRef.evt,
        prev: eventRef.prev,
        ledgerPath,
        reason: "EVT memory event hash is invalid and was not appended."
      };
    }

    const readResult = await readEvtMemoryLedger(ledgerPath);

    if (readResult.status === "FAILED") {
      return {
        status: "FAILED",
        evt: eventRef.evt,
        prev: eventRef.prev,
        ledgerPath,
        reason: `EVT memory ledger read failed before append: ${readResult.reason}`
      };
    }

    const continuity = validateMemoryAppendContinuity(readResult.events, event);

    if (!continuity.ok) {
      return {
        status: "REJECTED",
        evt: eventRef.evt,
        prev: eventRef.prev,
        ledgerPath,
        reason: continuity.reason
      };
    }

    await appendFile(ledgerPath, `${buildEvtMemoryEventLine(event)}\n`, "utf8");

    return {
      status: "APPENDED",
      evt: eventRef.evt,
      prev: eventRef.prev,
      ledgerPath,
      reason: "EVT memory event appended to memory ledger."
    };
  } catch (error) {
    return {
      status: "FAILED",
      evt: eventRef.evt,
      prev: eventRef.prev,
      ledgerPath,
      reason:
        error instanceof Error
          ? error.message
          : "Unknown EVT memory ledger append failure."
    };
  }
}

export async function appendEvtMemoryEvents(
  events: EvtMemoryEvent[],
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerAppendResult[]> {
  const results: EvtMemoryLedgerAppendResult[] = [];

  for (const event of events) {
    results.push(await appendEvtMemoryEvent(event, ledgerPath));
  }

  return results;
}

export async function readEvtMemoryLedger(
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerReadResult> {
  try {
    await ensureEvtMemoryLedger(ledgerPath);

    const raw = await readFile(ledgerPath, "utf8");

    if (!raw.trim()) {
      return {
        status: "EMPTY",
        ledgerPath,
        events: [],
        invalidLines: 0,
        reason: "EVT memory ledger exists but contains no events."
      };
    }

    const lines = raw
      .split("\n")
      .map((line) => line.trim())
      .filter(Boolean);

    const events: EvtMemoryEvent[] = [];
    let invalidLines = 0;

    for (const line of lines) {
      const event = parseEvtMemoryEventLine(line);

      if (!event) {
        invalidLines += 1;
        continue;
      }

      events.push(event);
    }

    return {
      status: events.length > 0 ? "READY" : "EMPTY",
      ledgerPath,
      events,
      invalidLines,
      reason:
        invalidLines > 0
          ? "EVT memory ledger read completed with invalid lines."
          : "EVT memory ledger read completed."
    };
  } catch (error) {
    return {
      status: "FAILED",
      ledgerPath,
      events: [],
      invalidLines: 0,
      reason:
        error instanceof Error
          ? error.message
          : "Unknown EVT memory ledger read failure."
    };
  }
}

export async function readEvtMemoryEvents(
  limit?: number,
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryEvent[]> {
  const result = await readEvtMemoryLedger(ledgerPath);

  if (typeof limit === "number" && limit > 0) {
    return result.events.slice(-limit);
  }

  return result.events;
}

export async function findEvtMemoryEventById(
  evt: string,
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerLookupResult> {
  const normalizedEvt = evt.trim();

  if (!normalizedEvt) {
    return {
      found: false,
      ledgerPath,
      reason: "No EVT memory identifier was provided."
    };
  }

  const events = await readEvtMemoryEvents(undefined, ledgerPath);
  const event = events.find((item) => item.evt === normalizedEvt);

  if (!event) {
    return {
      found: false,
      ledgerPath,
      reason: `EVT memory event ${normalizedEvt} was not found.`
    };
  }

  return {
    found: true,
    event,
    ledgerPath,
    reason: `EVT memory event ${normalizedEvt} found.`
  };
}

export async function getEvtMemoryEventById(
  evt: string,
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryEvent | null> {
  const result = await findEvtMemoryEventById(evt, ledgerPath);

  return result.event ?? null;
}

export async function getLastEvtMemoryEvent(input?: {
  ipr?: string;
  sessionId?: string;
  ledgerPath?: string;
}): Promise<EvtMemoryEvent | null> {
  const events = await readEvtMemoryEvents(undefined, input?.ledgerPath);

  const filtered = events.filter((event) => {
    if (input?.ipr && event.ipr !== input.ipr) {
      return false;
    }

    if (input?.sessionId && event.sessionId !== input.sessionId) {
      return false;
    }

    return true;
  });

  return filtered[filtered.length - 1] ?? null;
}

export async function getLastEvtMemoryEventReference(input?: {
  ipr?: string;
  sessionId?: string;
  ledgerPath?: string;
}): Promise<string> {
  const lastEvent = await getLastEvtMemoryEvent(input);

  return lastEvent?.evt ?? "GENESIS";
}

export async function buildEvtMemoryLedgerSummary(
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerSummary> {
  const readResult = await readEvtMemoryLedger(ledgerPath);
  const lastEvent = readResult.events[readResult.events.length - 1];
  const integrity = await verifyEvtMemoryLedger(ledgerPath);

  return {
    ledgerPath,
    totalEvents: readResult.events.length,
    lastEvent: lastEvent?.evt ?? "GENESIS",
    lastTraceHash: lastEvent?.anchors.traceHash ?? "",
    invalidLines: readResult.invalidLines,
    verificationStatus: integrity.status
  };
}

export async function verifyEvtMemoryLedger(
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerIntegrityResult> {
  const readResult = await readEvtMemoryLedger(ledgerPath);
  const events = readResult.events;

  const hashValid = events.every((event) => isEvtMemoryEventHashValid(event));
  const chainContinuity = inferChainContinuity(events);

  const warnings = buildWarnings({
    totalEvents: events.length,
    invalidLines: readResult.invalidLines,
    hashValid,
    chainContinuity
  });

  return {
    status: inferVerificationStatus({
      totalEvents: events.length,
      invalidLines: readResult.invalidLines,
      hashValid,
      chainContinuity
    }),
    ledgerPath,
    totalEvents: events.length,
    invalidLines: readResult.invalidLines,
    hashValid,
    chainContinuity,
    warnings
  };
}

export async function exportPublicEvtMemoryLedgerView(
  limit?: number,
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<EvtMemoryLedgerPublicEvent[]> {
  const events = await readEvtMemoryEvents(limit, ledgerPath);

  return events.map((event) => toPublicEvtMemoryEvent(event));
}

export async function clearEvtMemoryLedgerForLocalDevelopmentOnly(
  ledgerPath = DEFAULT_EVT_MEMORY_LEDGER_FILE
): Promise<void> {
  await ensureEvtMemoryLedger(ledgerPath);
  await writeFile(ledgerPath, "", "utf8");
}

export async function buildEvtMemoryContextFromLedger(input: {
  sessionId: string;
  ipr: string;
  message: string;
  ledgerPath?: string;
}): Promise<LedgerMemoryContext> {
  const readResult = await readEvtMemoryLedger(input.ledgerPath);

  if (readResult.events.length === 0) {
    return {
      used: false,
      source: "NONE",
      text: "Nessuna memoria EVT/IPR-bound disponibile nel ledger semantico.",
      semanticState: null,
      lastEventId: null
    };
  }

  const sessionEvents = readResult.events.filter(
    (event) => event.ipr === input.ipr && event.sessionId === input.sessionId
  );

  if (sessionEvents.length > 0) {
    const semanticState = buildSemanticStateFromEvents({
      ipr: input.ipr,
      sessionId: input.sessionId,
      events: sessionEvents
    });

    return {
      used: true,
      source: "LEDGER_SESSION",
      text: buildLedgerMemoryText({
        source: "LEDGER_SESSION",
        semanticState,
        events: sessionEvents
      }),
      semanticState,
      lastEventId: semanticState.lastEventId
    };
  }

  const canonicalEvents = readResult.events.filter(
    (event) =>
      event.ipr === input.ipr && event.sessionId === CANONICAL_SESSION_ID
  );

  if (canonicalEvents.length > 0) {
    const semanticState = buildSemanticStateFromEvents({
      ipr: input.ipr,
      sessionId: CANONICAL_SESSION_ID,
      events: canonicalEvents
    });

    return {
      used: true,
      source: "LEDGER_IPR_CANONICAL",
      text: buildLedgerMemoryText({
        source: "LEDGER_IPR_CANONICAL",
        semanticState,
        events: canonicalEvents
      }),
      semanticState,
      lastEventId: semanticState.lastEventId
    };
  }

  const recentEvents = selectRelevantRecentEvents({
    events: readResult.events.filter((event) => event.ipr === input.ipr),
    message: input.message
  });

  if (recentEvents.length > 0) {
    const sessionId =
      recentEvents[recentEvents.length - 1]?.sessionId || input.sessionId;

    const semanticState = buildSemanticStateFromEvents({
      ipr: input.ipr,
      sessionId,
      events: recentEvents
    });

    return {
      used: true,
      source: "LEDGER_IPR_RECENT",
      text: buildLedgerMemoryText({
        source: "LEDGER_IPR_RECENT",
        semanticState,
        events: recentEvents
      }),
      semanticState,
      lastEventId: semanticState.lastEventId
    };
  }

  return {
    used: false,
    source: "NONE",
    text: "Nessuna memoria EVT/IPR-bound rilevante disponibile nel ledger semantico.",
    semanticState: null,
    lastEventId: null
  };
}

export function buildEvtMemoryTracePayload(event: EvtMemoryEvent) {
  return {
    evt: event.evt,
    prev: event.prev,
    t: event.t,
    entity: event.entity,
    ipr: event.ipr,
    sessionId: event.sessionId,
    kind: event.kind,
    runtimeRole: event.runtimeRole,
    state: event.state,
    decision: event.decision,
    contextClass: event.contextClass,
    documentMode: event.documentMode,
    documentFamily: event.documentFamily,
    projectDomain: event.projectDomain,
    activeDomains: event.activeDomains,
    activeDocument: event.activeDocument,
    semanticTags: event.semanticTags,
    userIntent: event.userIntent,
    memoryDelta: event.memoryDelta,
    nextContext: event.nextContext,
    governedEvt: event.governedEvt,
    governedHash: event.governedHash,
    opcProofId: event.opcProofId,
    opcChainHash: event.opcChainHash,
    inputHash: event.anchors.inputHash,
    outputHash: event.anchors.outputHash
  };
}

export function rebuildEvtMemoryEventHash(event: EvtMemoryEvent): string {
  return sha256Short(buildEvtMemoryTracePayload(event));
}

export function isEvtMemoryEventHashValid(event: EvtMemoryEvent): boolean {
  return rebuildEvtMemoryEventHash(event) === event.anchors.traceHash;
}

export function isEvtMemoryEventStructurallyValid(
  event: Partial<EvtMemoryEvent>
): event is EvtMemoryEvent {
  return Boolean(
    event.evt &&
      event.prev &&
      event.t &&
      event.entity &&
      event.ipr &&
      event.sessionId &&
      event.kind === EVENT_KIND &&
      event.runtimeRole === RUNTIME_ROLE &&
      event.state &&
      event.decision &&
      event.contextClass &&
      event.documentMode &&
      event.documentFamily &&
      event.projectDomain &&
      Array.isArray(event.activeDomains) &&
      Array.isArray(event.semanticTags) &&
      typeof event.userIntent === "string" &&
      typeof event.memoryDelta === "string" &&
      typeof event.nextContext === "string" &&
      event.anchors?.inputHash &&
      event.anchors?.outputHash &&
      event.anchors?.traceHash &&
      event.anchors?.memoryHash &&
      event.boundary &&
      event.boundary.legalCertification === false
  );
}

export function getEvtMemoryEventMissingFields(
  event: Partial<EvtMemoryEvent>
): string[] {
  const missing: string[] = [];

  if (!event.evt) missing.push("evt");
  if (!event.prev) missing.push("prev");
  if (!event.t) missing.push("t");
  if (!event.entity) missing.push("entity");
  if (!event.ipr) missing.push("ipr");
  if (!event.sessionId) missing.push("sessionId");
  if (event.kind !== EVENT_KIND) missing.push("kind");
  if (event.runtimeRole !== RUNTIME_ROLE) missing.push("runtimeRole");
  if (!event.state) missing.push("state");
  if (!event.decision) missing.push("decision");
  if (!event.contextClass) missing.push("contextClass");
  if (!event.documentMode) missing.push("documentMode");
  if (!event.documentFamily) missing.push("documentFamily");
  if (!event.projectDomain) missing.push("projectDomain");
  if (!Array.isArray(event.activeDomains)) missing.push("activeDomains");
  if (!Array.isArray(event.semanticTags)) missing.push("semanticTags");
  if (typeof event.userIntent !== "string") missing.push("userIntent");
  if (typeof event.memoryDelta !== "string") missing.push("memoryDelta");
  if (typeof event.nextContext !== "string") missing.push("nextContext");
  if (!event.anchors?.inputHash) missing.push("anchors.inputHash");
  if (!event.anchors?.outputHash) missing.push("anchors.outputHash");
  if (!event.anchors?.traceHash) missing.push("anchors.traceHash");
  if (!event.anchors?.memoryHash) missing.push("anchors.memoryHash");
  if (!event.boundary) missing.push("boundary");
  if (event.boundary?.legalCertification !== false) {
    missing.push("boundary.legalCertification");
  }

  return missing;
}

export function buildEvtMemoryEventLine(event: EvtMemoryEvent): string {
  return JSON.stringify(event);
}

export function parseEvtMemoryEventLine(line: string): EvtMemoryEvent | null {
  try {
    const parsed = JSON.parse(line) as EvtMemoryEvent;

    if (!isEvtMemoryEventStructurallyValid(parsed)) {
      return null;
    }

    if (!isEvtMemoryEventHashValid(parsed)) {
      return null;
    }

    return parsed;
  } catch {
    return null;
  }
}

export function toPublicEvtMemoryEvent(
  event: EvtMemoryEvent
): EvtMemoryLedgerPublicEvent {
  return {
    evt: event.evt,
    prev: event.prev,
    t: event.t,
    entity: event.entity,
    ipr: event.ipr,
    sessionId: event.sessionId,
    state: event.state,
    decision: event.decision,
    documentFamily: event.documentFamily,
    projectDomain: event.projectDomain,
    activeDomains: event.activeDomains,
    activeDocument: event.activeDocument,
    semanticTags: event.semanticTags,
    userIntent: event.userIntent,
    governedEvt: event.governedEvt,
    governedHash: event.governedHash,
    opcProofId: event.opcProofId,
    opcChainHash: event.opcChainHash,
    traceHash: event.anchors.traceHash,
    memoryHash: event.anchors.memoryHash,
    legalCertification: false
  };
}

export function buildSemanticStateFromEvents(input: {
  ipr: string;
  sessionId: string;
  events: EvtMemoryEvent[];
}): SemanticState {
  const ordered = [...input.events].sort((a, b) => {
    return Date.parse(a.t) - Date.parse(b.t);
  });

  const lastEvent = ordered[ordered.length - 1] ?? null;
  const activeDocument = getLastNonEmpty(
    ordered.map((event) => event.activeDocument)
  );

  const documentFamily =
    getLastNonGeneralDocumentFamily(
      ordered.map((event) => event.documentFamily)
    ) || "GENERAL_DOCUMENT";

  const projectDomain =
    getLastNonGeneralProjectDomain(
      ordered.map((event) => event.projectDomain)
    ) || "GENERAL";

  const activeDomains = mergeUnique(
    ordered.flatMap((event) => event.activeDomains || []),
    8
  ) as ProjectDomain[];

  const centralThesis = extractCentralThesisFromEvents(ordered);

  const semanticTags = mergeUnique(
    ordered.flatMap((event) => event.semanticTags),
    64
  );

  const referenceRules = buildReferenceRulesFromEvents(ordered);

  const accumulatedMeaning = ordered
    .map((event) => event.memoryDelta)
    .filter(Boolean)
    .join(" ")
    .slice(-4500);

  return {
    ipr: input.ipr,
    sessionId: input.sessionId,
    runtimeRole: RUNTIME_ROLE,
    activeDocument,
    documentFamily,
    projectDomain,
    activeDomains: activeDomains.length > 0 ? activeDomains : ["GENERAL"],
    centralThesis,
    semanticTags,
    referenceRules,
    accumulatedMeaning,
    lastEventId: lastEvent?.evt ?? null,
    lastGovernedEvt: getLastNonEmpty(ordered.map((event) => event.governedEvt)),
    lastGovernedHash: getLastNonEmpty(
      ordered.map((event) => event.governedHash)
    ),
    lastOpcProofId: getLastNonEmpty(ordered.map((event) => event.opcProofId)),
    lastOpcChainHash: getLastNonEmpty(ordered.map((event) => event.opcChainHash)),
    updatedAt: lastEvent?.t ?? new Date().toISOString()
  };
}

function buildLedgerMemoryText(input: {
  source: LedgerMemoryContext["source"];
  semanticState: SemanticState;
  events: EvtMemoryEvent[];
}): string {
  const recentEvents = input.events.slice(-MAX_CONTEXT_EVENTS);

  return [
    "MEMORIA EVT/IPR-BOUND RICOSTRUITA DA LEDGER:",
    `MEMORY_SOURCE: ${input.source}`,
    `RUNTIME_ROLE: ${input.semanticState.runtimeRole}`,
    `IPR: ${input.semanticState.ipr}`,
    `SESSION_ID: ${input.semanticState.sessionId}`,
    `PROJECT_DOMAIN: ${input.semanticState.projectDomain}`,
    `ACTIVE_DOMAINS: ${input.semanticState.activeDomains.join(", ")}`,
    `ACTIVE_DOCUMENT: ${input.semanticState.activeDocument || "none"}`,
    `DOCUMENT_FAMILY: ${input.semanticState.documentFamily}`,
    `CENTRAL_THESIS: ${input.semanticState.centralThesis || "none"}`,
    `LAST_MEMORY_EVT: ${input.semanticState.lastEventId || "none"}`,
    `LAST_GOVERNED_EVT: ${input.semanticState.lastGovernedEvt || "none"}`,
    `LAST_GOVERNED_HASH: ${input.semanticState.lastGovernedHash || "none"}`,
    `LAST_OPC_PROOF: ${input.semanticState.lastOpcProofId || "none"}`,
    `LAST_OPC_CHAIN_HASH: ${input.semanticState.lastOpcChainHash || "none"}`,
    `SEMANTIC_TAGS: ${
      input.semanticState.semanticTags.length > 0
        ? input.semanticState.semanticTags.join(", ")
        : "none"
    }`,
    "",
    "REFERENCE_RULES:",
    input.semanticState.referenceRules.length > 0
      ? input.semanticState.referenceRules.join("\n")
      : "none",
    "",
    "ACCUMULATED_MEANING:",
    input.semanticState.accumulatedMeaning || "none",
    "",
    "RECENT_EVT_MEMORY_LEDGER:",
    ...recentEvents.map((event) =>
      [
        `- ${event.evt}`,
        `  prev: ${event.prev}`,
        `  projectDomain: ${event.projectDomain}`,
        `  activeDomains: ${event.activeDomains.join(", ")}`,
        `  governedEvt: ${event.governedEvt || "none"}`,
        `  governedHash: ${event.governedHash || "none"}`,
        `  opcProofId: ${event.opcProofId || "none"}`,
        `  opcChainHash: ${event.opcChainHash || "none"}`,
        `  family: ${event.documentFamily}`,
        `  activeDocument: ${event.activeDocument || "none"}`,
        `  intent: ${event.userIntent}`,
        `  delta: ${event.memoryDelta}`,
        `  nextContext: ${event.nextContext}`,
        `  traceHash: ${event.anchors.traceHash}`,
        `  memoryHash: ${event.anchors.memoryHash}`,
        `  legalCertification: ${event.boundary.legalCertification}`
      ].join("\n")
    ),
    "",
    "BOUNDARY:",
    NON_CERTIFICATION_STATEMENT,
    `U.S.E. democratic boundary: ${USE_DEMOCRATIC_BOUNDARY}`,
    `HBCE ECOSISTEMA AI boundary: ${HBCE_AI_BOUNDARY}`,
    "",
    "ISTRUZIONE DI RECUPERO:",
    "Questa memoria è stata ricostruita dal ledger semantico. Usala come continuità IPR-bound quando la memoria volatile di sessione non è disponibile. Non usare questa memoria per collegare identità personale e contenuto di una scelta democratica. Se emergono riferimenti a HBCE ECOSISTEMA AI, AI governance, modelli esterni, OpenAI, Anthropic, audit AI o IPR AI Audit Trail, recupera il dominio HBCE_ECOSISTEMA_AI e la sua boundary: il modello AI non governa HBCE; HBCE governa l’uso dei modelli AI."
  ]
    .join("\n")
    .slice(0, MAX_CONTEXT_TEXT_CHARS);
}

function selectRelevantRecentEvents(input: {
  events: EvtMemoryEvent[];
  message: string;
}): EvtMemoryEvent[] {
  const scored = input.events
    .map((event) => ({
      event,
      score: scoreEventForMessage(event, input.message),
      timestamp: Date.parse(event.t) || 0
    }))
    .filter((item) => item.score > 0)
    .sort((a, b) => {
      if (b.score !== a.score) {
        return b.score - a.score;
      }

      return b.timestamp - a.timestamp;
    });

  if (scored.length === 0) {
    return input.events.slice(-MAX_CONTEXT_EVENTS);
  }

  return scored
    .slice(0, MAX_CONTEXT_EVENTS)
    .map((item) => item.event)
    .sort((a, b) => Date.parse(a.t) - Date.parse(b.t));
}

function scoreEventForMessage(event: EvtMemoryEvent, message: string): number {
  const normalizedMessage = normalizeForMatch(message);
  const messageTags = detectTags(message);

  let score = 0;

  for (const tag of messageTags) {
    if (event.semanticTags.includes(tag)) {
      score += 10;
    }
  }

  if (
    event.activeDocument &&
    normalizedMessage.includes(normalizeForMatch(event.activeDocument))
  ) {
    score += 15;
  }

  if (
    event.documentFamily !== "GENERAL_DOCUMENT" &&
    normalizedMessage.includes(normalizeForMatch(event.documentFamily))
  ) {
    score += 8;
  }

  if (
    event.documentFamily === "HBCE_ECOSISTEMA_AI" ||
    event.projectDomain === "HBCE_ECOSISTEMA_AI"
  ) {
    const hbceAiTerms = [
      "hbce ecosistema ai",
      "ecosistema ai",
      "ai governance",
      "governance ai",
      "governo dell ai",
      "governare l ai",
      "ai audit",
      "ipr ai audit trail",
      "model governance",
      "governance modelli",
      "modelli ai",
      "openai",
      "anthropic",
      "claude",
      "gemini",
      "mistral",
      "runtime governato"
    ];

    if (
      hbceAiTerms.some((term) =>
        normalizedMessage.includes(normalizeForMatch(term))
      )
    ) {
      score += 24;
    }
  }

  if (event.documentFamily === "USE" || event.projectDomain === "U.S.E.") {
    const useTerms = [
      "u.s.e.",
      "use",
      "united states of europe",
      "stati uniti d europa",
      "voto digitale federato",
      "referendum",
      "consultazione pubblica",
      "federazione europea",
      "sovranita digitale",
      "sovranità digitale"
    ];

    if (useTerms.some((term) => normalizedMessage.includes(normalizeForMatch(term)))) {
      score += 22;
    }
  }

  if (event.documentFamily === "HBCE_RUNTIME") {
    const runtimeTerms = [
      "joker",
      "joker-c2",
      "ipr",
      "evt",
      "memoria",
      "opc",
      "proof receipt",
      "ledger",
      "runtime",
      "route",
      "fail closed",
      "fail-closed",
      "programmazione",
      "ripara",
      "danno"
    ];

    if (runtimeTerms.some((term) => normalizedMessage.includes(term))) {
      score += 20;
    }
  }

  const updatedAt = Date.parse(event.t);

  if (Number.isFinite(updatedAt)) {
    const hours = Math.max(1, (Date.now() - updatedAt) / (1000 * 60 * 60));
    score += Math.max(0, 10 - Math.floor(hours / 12));
  }

  return score;
}

