function normalizeForMatch(value: string): string {
  return value
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[’']/g, " ")
    .replace(/[^\p{L}\p{N}./_-]+/gu, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getLastNonEmpty(values: Array<string | null | undefined>): string | null {
  for (let index = values.length - 1; index >= 0; index -= 1) {
    const value = values[index];

    if (typeof value === "string" && value.trim()) {
      return value.trim();
    }
  }

  return null;
}

function getLastNonGeneralDocumentFamily(
  values: DocumentFamily[]
): DocumentFamily | null {
  for (let index = values.length - 1; index >= 0; index -= 1) {
    const value = values[index];

    if (value && value !== "GENERAL_DOCUMENT") {
      return value;
    }
  }

  return null;
}

function getLastNonGeneralProjectDomain(
  values: ProjectDomain[]
): ProjectDomain | null {
  for (let index = values.length - 1; index >= 0; index -= 1) {
    const value = values[index];

    if (value && value !== "GENERAL") {
      return value;
    }
  }

  return null;
}

function extractCentralThesisFromEvents(events: EvtMemoryEvent[]): string | null {
  for (let index = events.length - 1; index >= 0; index -= 1) {
    const event = events[index];
    const match = event?.memoryDelta.match(
      /Tesi centrale incorporata:\s*(.+?)(?:\s+Regola di continuità|\s+Regola di sicurezza|$)/
    );

    if (match?.[1]?.trim()) {
      return match[1].trim();
    }
  }

  return null;
}

function buildReferenceRulesFromEvents(events: EvtMemoryEvent[]): string[] {
  const rules: string[] = [];

  for (const event of events) {
    if (event.activeDocument && event.documentFamily === "APOKALYPSIS") {
      rules.push(
        `"questa opera", "questo testo", "Apokalypsis", "i punti forti" = ${event.activeDocument}`
      );
    }

    if (
      event.documentFamily === "HBCE_ECOSISTEMA_AI" ||
      event.projectDomain === "HBCE_ECOSISTEMA_AI"
    ) {
      rules.push(
        `"HBCE ECOSISTEMA AI", "ecosistema AI", "AI governance", "governance AI", "audit AI", "modelli AI" = contesto HBCE_ECOSISTEMA_AI attivo`
      );
      rules.push(`boundary AI governance = ${HBCE_AI_BOUNDARY}`);
    }

    if (event.documentFamily === "USE" || event.projectDomain === "U.S.E.") {
      rules.push(
        `"U.S.E.", "voto digitale federato", "consultazione pubblica", "referendum" = contesto U.S.E. attivo`
      );
      rules.push(`regola democratica U.S.E. = ${USE_DEMOCRATIC_BOUNDARY}`);
    }

    if (event.documentFamily === "HBCE_RUNTIME") {
      rules.push(
        `"JOKER-C2", "IPR", "EVT", "memoria", "OPC", "proof receipt", "ledger", "runtime", "fail-closed" = contesto HBCE_RUNTIME attivo`
      );
    }

    if (event.activeDocument) {
      rules.push(`documento attivo = ${event.activeDocument}`);
    }

    if (event.governedEvt) {
      rules.push(`ultimo governed EVT = ${event.governedEvt}`);
    }

    if (event.opcProofId) {
      rules.push(`ultimo OPC proof receipt = ${event.opcProofId}`);
    }
  }

  return mergeUnique(rules, 24);
}

function mergeUnique(values: string[], limit = 32): string[] {
  return Array.from(new Set(values.filter(Boolean))).slice(0, limit);
}

function validateMemoryAppendContinuity(
  events: EvtMemoryEvent[],
  nextEvent: EvtMemoryEvent
): { ok: boolean; reason: string } {
  if (!nextEvent.prev || !nextEvent.prev.trim()) {
    return {
      ok: false,
      reason: "Memory append rejected: next event has no previous reference."
    };
  }

  if (events.length === 0) {
    return {
      ok: true,
      reason:
        nextEvent.prev === "GENESIS"
          ? "First memory event references GENESIS."
          : `First memory event references external runtime anchor ${nextEvent.prev}.`
    };
  }

  const sameSessionEvents = events.filter((event) => {
    return event.ipr === nextEvent.ipr && event.sessionId === nextEvent.sessionId;
  });

  const sameCanonicalEvents = events.filter((event) => {
    return event.ipr === nextEvent.ipr && event.sessionId === CANONICAL_SESSION_ID;
  });

  const relevantEvents =
    sameSessionEvents.length > 0
      ? sameSessionEvents
      : sameCanonicalEvents.length > 0
        ? sameCanonicalEvents
        : [];

  if (relevantEvents.length === 0) {
    return {
      ok: true,
      reason:
        nextEvent.prev === "GENESIS"
          ? "New memory chain starts from GENESIS."
          : `New memory chain starts from external runtime anchor ${nextEvent.prev}.`
    };
  }

  const lastRelevant = relevantEvents[relevantEvents.length - 1];

  if (!lastRelevant) {
    return {
      ok: false,
      reason: "Memory append rejected: last relevant memory event is unavailable."
    };
  }

  if (nextEvent.prev !== lastRelevant.evt) {
    return {
      ok: false,
      reason:
        `Memory append rejected: next prev=${nextEvent.prev} does not match last relevant memory evt=${lastRelevant.evt}.`
    };
  }

  return {
    ok: true,
    reason: "Memory append continuity OK."
  };
}

function inferChainContinuity(
  events: EvtMemoryEvent[]
): EvtMemoryLedgerIntegrityResult["chainContinuity"] {
  if (events.length === 0) {
    return "UNVERIFIED";
  }

  const groups = groupEventsByIprAndSession(events);
  let hasPartial = false;

  for (const groupedEvents of groups.values()) {
    const ordered = [...groupedEvents].sort((a, b) => Date.parse(a.t) - Date.parse(b.t));

    if (ordered.length === 0) {
      continue;
    }

    if (!ordered[0]?.prev) {
      hasPartial = true;
      continue;
    }

    for (let index = 1; index < ordered.length; index += 1) {
      const current = ordered[index];
      const previous = ordered[index - 1];

      if (!current || !previous || current.prev !== previous.evt) {
        hasPartial = true;
        break;
      }
    }
  }

  return hasPartial ? "PARTIAL" : "LINEAR";
}

function groupEventsByIprAndSession(
  events: EvtMemoryEvent[]
): Map<string, EvtMemoryEvent[]> {
  const groups = new Map<string, EvtMemoryEvent[]>();

  for (const event of events) {
    const key = `${event.ipr}::${event.sessionId}`;
    const current = groups.get(key) || [];

    current.push(event);
    groups.set(key, current);
  }

  return groups;
}

function inferVerificationStatus(input: {
  totalEvents: number;
  invalidLines: number;
  hashValid: boolean;
  chainContinuity: EvtMemoryLedgerIntegrityResult["chainContinuity"];
}): EvtMemoryLedgerVerificationStatus {
  if (input.totalEvents === 0) {
    return "UNVERIFIED";
  }

  if (input.invalidLines > 0 || !input.hashValid) {
    return "INVALID";
  }

  if (input.chainContinuity === "PARTIAL") {
    return "PARTIAL";
  }

  return "VERIFIABLE";
}

function buildWarnings(input: {
  totalEvents: number;
  invalidLines: number;
  hashValid: boolean;
  chainContinuity: EvtMemoryLedgerIntegrityResult["chainContinuity"];
}): string[] {
  const warnings: string[] = [];

  if (input.totalEvents === 0) {
    warnings.push("EVT memory ledger contains no events.");
  }

  if (input.invalidLines > 0) {
    warnings.push(
      `EVT memory ledger contains ${input.invalidLines} invalid line(s).`
    );
  }

  if (!input.hashValid) {
    warnings.push("One or more EVT memory event hashes are invalid.");
  }

  if (input.chainContinuity === "PARTIAL") {
    warnings.push(
      "EVT memory ledger is partially ordered by IPR/session. This can happen when multiple sessions or canonical IPR memory slots write independent chains to the same ledger."
    );
  }

  return Array.from(new Set(warnings));
}
